        const posColor = pos === 'Operator' ? '#f59e0b' : pos === 'Master' ? '#3b82f6' : pos === 'Mexanik' ? '#22c55e' : pos === 'Uzlavyaz' ? '#a855f7' : '#ec4899';
        return (
          <div key={pos} style={{ marginBottom: '2rem' }}>
            <h3 style={{ fontSize: '1.1rem', fontWeight: 800, color: posColor, marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
