                    <th style={thStyle}>Amallar</th>
                  </tr>
                </thead>
                <tbody>
                  {workers.filter(op => op.shift_type === 'KUNDUZ').map(op => renderWorkerRow(op, '#f59e0b'))}
                  {workers.filter(op => op.shift_type === 'TUNGI').map(op => renderWorkerRow(op, '#6366f1'))}
                </tbody>
              </table>
            </div>
          </div>
        );
      })}
    </div>
  );
};

